body {
  font-family: 'Open Sans', sans-serif;
  /* Fluid font size: min 1rem, max 1.25rem, ideal 2vw */
  font-size: clamp(1rem, 2vw + 0.5rem, 1.25rem);
  line-height: 1.6;
}

h1 {
  font-family: 'Roboto Slab', serif;
  /* Fluid heading size: min 2rem, max 4rem, ideal 5vw */
  font-size: clamp(2rem, 5vw + 1rem, 4rem);
  line-height: 1.1;
  text-wrap: balance; /* Modern enhancement for better headlines */
}
